1	import { log } from "cc";
2	import { BaseState, SlotBottomBarState, commonGameManager, eventManager, newBottombarManager, newExtraManager } from "db://astarte-framework/Managers";
3	import GameView from "../GameView";
4	import { roundController, tempoSetting, tools } from "db://astarte-framework/utilis";
5	import { MULTIPLIER_EVENT } from "../Multiplier/MultiplierManager";
6	
7	export class RoundEndState extends BaseState
8	{
9	    private m_gameView: GameView = null;
10	    private m_processTick: number = 0;
11	    private m_isChecking: boolean = false;
12	
13	    constructor( gameView: GameView )
14	    {
15	        super();
16	        this.m_gameView = gameView;
17	    }
18	
19	    public async OnEnter()
20	    {
21	        log( "OnEnter state : ROUND_END" );
22	
23	        const isNoWin = this.m_gameView.RoundInfo.RoundWin === 0;
24	
25	        // 不是FG和RespinGame的話要歸零
26	        if ( !this.m_gameView.IsFreeGame && !this.m_gameView.IsGoingToFree && !this.m_gameView.IsRespinGame )
27	        {
28	            // 記得 歸0
29	            this.m_gameView.Win = 0;
30	
31	            // 盤面Index回復
32	            this.m_gameView.CurPlateIndex = -1;
33	
34	            if ( newExtraManager.IsFeaturesDemoMode )
35	            {
36	                this.m_gameView.EffectPlate.StopOneLineShow();
37	                newExtraManager.CheckBuyBonusOverAni();
38	                this.m_gameView.ClearAll();
39	            }
40	
41	            // 重置倍數到初始值
42	            this.ResetMultiplierToBase();
43	        }
44	        
45	        this.m_isChecking = true;
46	        await this.CheckAndPlayActivateEffectEnd();
47	
48	        this.m_gameView.CanSpaceStop = true;
49	        this.m_gameView.CanPlateStop = true;
50	
51	        if (this.m_gameView.SkipFreeGameNoWinDelay) {
52	            // BC-3：EnterFreeState 表演結束直接進 FG 第一手，跳過 0.5s noWin 緩衝（讀完即清）
53	            this.m_processTick = 0;
54	            this.m_gameView.SkipFreeGameNoWinDelay = false;
55	        }
56	        else if (!this.m_gameView.IsFirstRound && this.m_gameView.IsFreeGame && isNoWin) {
57	            this.m_processTick = 0.5;
58	        }
59	        else {
60	            if (newBottombarManager.IsAutoSpin) {
61	                // 轉輪節奏模組：三幣瑞龍
62	                this.m_processTick = tempoSetting.TempoSetting.TripleCoinTreasure.AUTO_DELAY_TIME;
63	            }
64	            else {
65	                this.m_processTick = 0;
66	            }
67	        }
68	
69	        this.m_gameView.RetryRoundEnd();
70	
71	        this.m_isChecking = false;
72	    }
73	
74	    public OnProcess( dt: number )
75	    {
76	        if (this.m_isChecking) {
77	            return;
78	        }
79	
80	        // BC-3：EnterFreeState 表演結束 → RoundEndState → FG 第一手 SpinState 路徑期間，
81	        // 轉輪仍在轉動，補推進 Spin(dt) 消除視覺停頓（BC-1 視覺連續的實現手段）。
82	        // BC-2：其他 RoundEnd 路徑（BG 結算 / FG 後續手 / Respin 結算）IsFreeGame=false 或 IsStop=true，條件不成立、行為與原本一致。
83	        if ( this.m_gameView.IsFreeGame && !this.m_gameView.SlotReels.IsStop )
84	        {
85	            this.m_gameView.SlotReels.Spin( dt );
86	        }
87	
88	        this.m_processTick = tools.strip( this.m_processTick - dt );
89	        if ( this.m_processTick > 0
90	            || !roundController.CanToNextRound()
91	            || ( commonGameManager.IsTwice && !commonGameManager.IsGetRoundEndAck ) )
92	        {
93	            return;
94	        }
95	
96	        // 離開特色，要將自動玩關閉
97	        if ( newExtraManager.IsFeaturesDemoMode && !newBottombarManager.IsAutoSpin )
98	        {
99	            newBottombarManager.ShowAutoPlayState( false );
100	            this.m_gameView.EffectPlate.CurAwardLines.length = 0;
101	        }
102	
103	        // 確認有無自動玩次數 要改變地bar顯示
104	        if ( newBottombarManager.IsAutoSpin && newBottombarManager.IsAutoPlayByTimes() )
105	        {
106	            newBottombarManager.SetSpinState( SlotBottomBarState.CLICK_STOP_IN_AUTOPLAY );
107	        }
108	
109	        this.m_gameView.ForEndToNext();
110	    }
111	
112	    public OnLeave()
113	    {
114	
115	    }
116	
117	    /**
118	     * @ch 重置倍數到初始值
119	     */
120	    private ResetMultiplierToBase(): void
121	    {
122	        const spinAck = this.m_gameView.SpinAck;
123	        eventManager.Dispatch( MULTIPLIER_EVENT.SET_INDEX, spinAck.MultiplierIndex, true, true );
124	        log( `Reset multiplier to base: ${spinAck.MultiplierIndex}` );
125	    }
126	
127	    /**
128	     * @ch 檢查發動動畫是否正在播放，如果正在播放則播放結束動畫
129	     */
130	    private async CheckAndPlayActivateEffectEnd(): Promise<void>
131	    {
132	        return new Promise<void>( (resolve) => {
133	            eventManager.Dispatch( MULTIPLIER_EVENT.GET_IS_ACTIVATE_EFFECT_PLAYING, (isPlaying: boolean) => {
134	                if (isPlaying) {
135	                    eventManager.Dispatch( MULTIPLIER_EVENT.PLAY_ACTIVATE_EFFECT_END );
136	                }
137	                resolve();
138	            });
139	        });
140	    }
141	}

1	import { error, log } from "cc";
2	import { newBottombarManager, BaseState, commonGameManager, SlotBottomBarState, stateManager, eventManager } from "db://astarte-framework/Managers";
3	import GameView from "../GameView";
4	import Game_Define from "../Game_Define";
5	import { roundController } from "db://astarte-framework/utilis";
6	import { FREE_GAME_ROUND_UI_EVENT } from "../FreeGame/FreeGameRoundUI";
7	import { REEL_UI_EVENT } from "../ReelUIManager";
8	import { PRE_WIN_EVENT, PreWinType } from "../PreWin/PreWinManager";
9	import { WaitUntil } from "../Common/AsyncUtils";
10	
11	export class SpinState extends BaseState
12	{
13	    private m_gameView: GameView = null;
14	
15	    private m_isPreWinEffectPlayed: boolean = false;
16	
17	    constructor( gameView: GameView )
18	    {
19	        super();
20	        this.m_gameView = gameView;
21	    }
22	
23	    public async OnEnter()
24	    {
25	        log( "OnEnter State : SPIN" );
26	
27	        roundController.StartSpin();
28	
29	        // 清理重複秀每條線
30	        this.m_gameView.EffectPlate.CurAwardLines.length = 0;
31	        this.m_gameView.EffectPlate.StopOneLineShow();
32	
33	        // spin前清理狀態
34	        this.m_gameView.ClearAll();
35	
36	        // 清除轉輪UI效果
37	        this.ClearReelUIEffect();
38	        
39	        // 在 OnRecvSpinAck 前記錄版本，用於 CheckPreWinEffect 判斷本局 SpinAck 是否已到
40	        const prevSpinAckVersion = this.m_gameView.SpinAckVersion;
41	
42	        // BC-7：EnterFreeState 表演結束直接接 FG 第一手的連續轉動旗標，讀完即清
43	        // 註：原本此處有 await Define.Wait(0.5) 等 FlyManager 晚到 callback 完成，
44	        //   現由 EnterFreeState dispatch FLY_EVENT.CANCEL_ADD_CASH_ANIMATION 直接取消晚到 callback，不需等待
45	        const continueSpin = this.m_gameView.IsFreeGameFirstSpinContinuous;
46	        if ( continueSpin )
47	        {
48	            this.m_gameView.IsFreeGameFirstSpinContinuous = false;
49	        }
50	
51	        if ( commonGameManager.HasUnshow )
52	        {
53	            commonGameManager.HasUnshow = false;
54	            this.m_gameView.IsHardStop = newBottombarManager.IsHardStop;
55	
56	            this.m_gameView.StartSpin( undefined, continueSpin );
57	            this.m_gameView.OnRecvSpinAck( this.m_gameView.UnshowSpinAck, true );
58	            this.m_gameView.UnshowSpinAck = null;
59	        }
60	        else
61	        {
62	            this.m_gameView.CurPlateIndex = this.m_gameView.CurPlateIndex + 1;
63	            // 重置標記，避免上一局殘留的 PreWinHandledIndex 誤觸 IF 分支
64	            this.m_gameView.PreWinHandledIndex = -1;
65	            this.m_gameView.StartSpin( undefined, continueSpin );
66	        }
67	
68	        await this.CheckPreWinEffect( prevSpinAckVersion );
69	
70	        // 宣告動畫完成後，統一設定盤面資料（含 SetPlateInfo → SetReelTimes）
71	        const nowRound = this.m_gameView.SpinAck.RoundQueue[ this.m_gameView.CurPlateIndex ];
72	        this.m_gameView.SetNowRoundInfo( nowRound );
73	
74	        // SetReelTimes 已執行，可安全呼叫快停
75	        if ( this.m_gameView.IsHardStop && !this.m_gameView.IsMgOmen )
76	        {
77	            this.m_gameView.SlotReels.ClickStopBtn();
78	        }
79	
80	        // FreeGame 專屬 UI 更新
81	        if ( this.m_gameView.IsFreeGame )
82	        {
83	            eventManager.Dispatch( FREE_GAME_ROUND_UI_EVENT.SET_NOW_ROUND, nowRound.FreeNowRound );
84	
85	            if ( !this.m_gameView.IsHardStop && !newBottombarManager.IsAutoSpin )
86	            {
87	                newBottombarManager.SetSpinState( SlotBottomBarState.START_SPIN );
88	            }
89	        }
90	    }
91	
92	    public OnProcess( dt: number )
93	    {
94	        this.m_gameView.SlotReels.Spin( dt );
95	        if ( !this.m_gameView.SlotReels.IsStop || this.m_isPreWinEffectPlayed || !this.m_gameView.SlotReels.IsEntryEffectDone )
96	        {
97	            return;
98	        }
99	
100	        this.m_gameView.CanPlateStop = true;
101	        this.m_gameView.CanSpaceStop = true;
102	        if ( !newBottombarManager.IsAutoSpin )
103	        {
104	            newBottombarManager.SetSpinState( SlotBottomBarState.CLICK_SPIN );
105	        }
106	
107	        stateManager.NextState( Game_Define.GameState.EFFECT_START );
108	    }
109	
110	    public OnLeave()
111	    {
112	 
113	    }
114	
115	    /**
116	     * @ch 播放預中效果動畫
117	     * @param mysteryEventKind 預中類型
118	     * @returns Promise 震動效果完成的 Promise
119	     */
120	    private async PlayPreWinEffect(mysteryEventKind: number): Promise<void> {
121	        return new Promise<void>((resolve) => {
122	            eventManager.Dispatch(PRE_WIN_EVENT.PLAY_PRE_WIN_ANIM, mysteryEventKind === 1 ? PreWinType.Scatter : PreWinType.Collect, resolve);
123	        });
124	    }
125	
126	    /**
127	     * @ch 檢查預中效果動畫
128	     * @param prevSpinAckVersion OnEnter 開始前記錄的 SpinAckVersion，用於 Base Game 判斷新的 SpinAck 是否已到
129	     * @returns Promise 預中效果完成的 Promise
130	     */
131	    private async CheckPreWinEffect( prevSpinAckVersion: number ): Promise<void> {
132	        this.m_isPreWinEffectPlayed = true;
133	        const currentIndex = this.m_gameView.CurPlateIndex;
134	
135	        if ( this.m_gameView.PreWinHandledIndex === currentIndex )
136	        {
137	            // OnRecvSpinAck 已為此 index 觸發動畫（Base Game 正常流程 / Unshow）
138	            // 直接等待該動畫結束即可
139	            await this.m_gameView.PreWinAnimPromise;
140	        }
141	        else if ( !this.m_gameView.IsFreeGame && !this.m_gameView.IsRespinGame )
142	        {
143	            // Base Game：OnRecvSpinAck 尚未到達，等待本局新的 SpinAck
144	            // 用版本號判斷，避免誤讀上一局的舊 SpinAck
145	            await WaitUntil( () => this.m_gameView.SpinAckVersion > prevSpinAckVersion );
146	            // OnRecvSpinAck 已設定 PreWinAnimPromise（有宣告時為動畫 Promise，否則為立即 resolve）
147	            await this.m_gameView.PreWinAnimPromise;
148	        }
149	        else
150	        {
151	            // FG / Respin 後續回合：SpinAck 資料已在首輪一次性到達，直接讀取
152	            if ( currentIndex < 0 )
153	            {
154	                error( "currentIndex is less than 0" );
155	            }
156	            const nowRound = this.m_gameView.SpinAck?.RoundQueue?.[ currentIndex ];
157	            if ( nowRound && nowRound.MysteryEventKind > 0 )
158	            {
159	                await this.PlayPreWinEffect( nowRound.MysteryEventKind );
160	            }
161	        }
162	
163	        this.m_isPreWinEffectPlayed = false;
164	    }
165	
166	    /**
167	     * @ch 清除轉輪UI效果
168	     */
169	    private ClearReelUIEffect()
170	    {
171	        if (!this.m_gameView.IsRespinGame)
172	        {
173	            eventManager.Dispatch(REEL_UI_EVENT.HIDE_LIGHT_LEFT_REEL);
174	            eventManager.Dispatch(REEL_UI_EVENT.HIDE_LIGHT_RIGHT_REEL);
175	        }
176	        eventManager.Dispatch(REEL_UI_EVENT.PREWIN_FRAME_FADE_OUT, -1);
177	    }
178	}

