1	import { _decorator } from "cc";
2	import GameView from "../GameView";
3	import { log } from "cc";
4	import { BaseState, eventManager, stateManager } from "db://astarte-framework/Managers";
5	import Game_Define from "../Game_Define";
6	import { RESPIN_UI_EVENT } from "../Respin/RespinUIManager";
7	import { Common } from "../Common/Common";
8	import { Define } from "db://astarte-framework/utilis";
9	
10	const { ccclass } = _decorator;
11	
12	@ccclass( "EnterRespinState" )
13	export class EnterRespinState extends BaseState
14	{
15	    private m_gameView: GameView = null;
16	
17	    /**@ch 等待時間（秒） */
18	    private static readonly WAIT_TIME = 0.8;
19	
20	    constructor( gameView: GameView )
21	    {
22	        super();
23	        this.m_gameView = gameView;
24	    }
25	
26	    public async OnEnter()
27	    {
28	        console.log( "OnEnter State: ENTER_RESPIN" );
29	
30	        await Define.Wait(this.m_gameView, EnterRespinState.WAIT_TIME);
31	
32	        if (this.m_gameView.IsGoingToRespinGame)
33	        {
34	            // 設定 Respin 狀態
35	            this.m_gameView.IsRespinGame = true;
36	            this.m_gameView.IsGoingToRespinGame = false;
37	
38	            this.m_gameView.ClearAll();
39	
40	            // 處理轉輪
41	            this.HandleReel();
42	        }
43	
44	        // 播放 Respin 進入動畫
45	        await this.PlayRespinEnterAnimation();
46	
47	        stateManager.NextState( Game_Define.GameState.ROUND_END );
48	    }
49	
50	    public OnProcess()
51	    {
52	
53	    }
54	
55	    public OnLeave()
56	    {
57	
58	    }
59	
60	    /**
61	     * @ch 處理轉輪
62	     */
63	    private HandleReel(): void
64	    {
65	        // 設定Respin鎖定列的旋轉鎖定
66	        Game_Define.RespinLockColumns.forEach( column => {
67	            this.m_gameView.SlotReels.SetColumnLock( column, true );
68	        } );
69	
70	        // 鎖定特定位置
71	        const nextRound = this.m_gameView.SpinAck.RoundQueue[this.m_gameView.CurPlateIndex + 1];
72	        const plateSymbol = ( nextRound?.FreePlateSymbol && nextRound.FreePlateSymbol.length > 0 )
73	            ? nextRound.FreePlateSymbol
74	            : nextRound?.MainPlateSymbol;
75	        nextRound?.RespinLockedPos?.forEach( ( serverPos: number ) =>
76	        {
77	            const decoded = Common.DecodeServerPosByRowConfig( serverPos );
78	            if ( !decoded )
79	            {
80	                console.warn( `[EnterRespinState] 無法解碼 RespinLockedPos: ${serverPos}` );
81	                return;
82	            }
83	
84	            const col = decoded.col;
85	            const row = decoded.row;
86	            const symbol = plateSymbol?.[ col ]?.Col?.[ row ]?.Symbol ?? -1;
87	            const number = plateSymbol?.[ col ]?.Col?.[ row ]?.Number ?? -1;
88	            if ( symbol < 0 )
89	            {
90	                console.warn( `[EnterRespinState] 找不到鎖定位置 Symbol: pos=${serverPos} => (${col},${row})` );
91	                return;
92	            }
93	
94	            console.log( `[EnterRespinState] 鎖定位置: pos=${serverPos} => (${col},${row}), symbol=${symbol}` );
95	
96	            // CollectAndRetrigger 在 Respin 鎖定時顯示為 Collect 靜態張
97	            const displaySymbol = ( symbol === Game_Define.Symbol.CollectAndRetrigger )
98	                ? Game_Define.Symbol.Collect
99	                : symbol;
100	
101	            // 清掉該位置殘留的 Spine 節點（停輪時建立的），避免蓋住靜態張
102	            this.m_gameView.EffectPlate.CleanSymbolSpineAt( col, row, Game_Define.LAYERS.TWO, false );
103	
104	            // 關閉原本格子的靜態圖，改用 EffectPlate 疊一張靜態圖
105	            this.m_gameView.SlotReels.AllColumns?.[ Game_Define.MIDDLE_PLATE_INDEX ]?.[ col ]?.HideSymbolByRow( row );
106	            this.m_gameView.EffectPlate.CreateSymbolStaticNode( col, row, displaySymbol, number);
107	        } );
108	    }
109	
110	    /**
111	     * @ch 播放 Respin 進入動畫
112	     */
113	    private async PlayRespinEnterAnimation(): Promise<void>
114	    {
115	        log( "=== PlayRespinEnterAnimation ===" );
116	
117	        await new Promise<void>((resolve) => {
118	            eventManager.Dispatch(RESPIN_UI_EVENT.PLAY_RESPI_DECLARE_ANIM, () => {
119	                log("Respin 宣告動畫播放完成");
120	                resolve();
121	            });
122	        });
123	    }
124	}

1	import { _decorator } from "cc";
2	import GameView from "../GameView";
3	import { log } from "cc";
4	import { BaseState, stateManager } from "db://astarte-framework/Managers";
5	import Game_Define from "../Game_Define";
6	
7	const { ccclass } = _decorator;
8	
9	@ccclass( "LeaveRespinState" )
10	export class LeaveRespinState extends BaseState
11	{
12	    private m_gameView: GameView = null;
13	
14	    /**
15	     * @ch 是否需要展示特色
16	     */
17	    public IsNeedFeatureDemo: boolean = false; 
18	
19	    constructor( gameView: GameView )
20	    {
21	        super();
22	        this.m_gameView = gameView;
23	    }
24	
25	    public async OnEnter()
26	    {
27	        log( "OnEnter State: LEAVE_RESPIN" );
28	
29	        // Respin 結束
30	        this.m_gameView.IsRespinGame = false;
31	
32	        // 解除Respin鎖定列的旋轉鎖定
33	        Game_Define.RespinLockColumns.forEach( column => {
34	            this.m_gameView.SlotReels.SetColumnLock( column, false );
35	        } );
36	
37	        // 檢查是否為免費遊戲的最後一輪
